def fibonacci(n):
    if n < 0:
        raise ValueError("n must be non-negative")
    if n <= 1:
        return n

    def multiply_matrices(A, B):
        a, b, c = A
        d, e, f = B
        return (
            a * d + b * e,
            a * e + b * f,
            b * e + c * f
        )

    def power(M, exp):
        result = (1, 0, 1)
        base = M
        while exp > 0:
            if exp & 1:
                result = multiply_matrices(result, base)
            base = multiply_matrices(base, base)
            exp >>= 1
        return result

    return power((1, 1, 0), n)[1]

